#include <bits/stdc++.h>
using namespace std;

const int N=70,mod=1e9+7;

int t,k,f[N][2][2],ans;
__int128 mi[N];
long long n,m;

long long g(long long n,long long m){
	if(n>=m)
		return (((__int128)(n-m))*m%mod+((__int128)m)*(m+1)/2%mod)%mod;
	return ((__int128)n)*(n+1)/2%mod;
}

void dfs(int l,int x,int y){
    if(~f[l][x][y])
        return;
    f[l][x][y]=0;
    int a=n/mi[l-1]%k,b=m/mi[l-1]%k;
    if(x==1 && y==1){
    	if(a>=b){
        	dfs(l-1,1,1);
        	f[l][x][y]=(f[l][x][y]+f[l-1][1][1])%mod;
        }
        if(a>b){
        	dfs(l-1,0,1);
        	f[l][x][y]=(f[l][x][y]+1LL*f[l-1][0][1]*(a-b))%mod;
        }
        dfs(l-1,1,0);
        f[l][x][y]=(f[l][x][y]+1LL*f[l-1][1][0]*min(b,a+1)%mod)%mod;
        dfs(l-1,0,0);
        f[l][x][y]=(f[l][x][y]+1LL*g(a,b)*f[l-1][0][0]%mod)%mod;
    }else if(x==0 && y==1){
        dfs(l-1,0,1);
        f[l][x][y]=(f[l][x][y]+1LL*f[l-1][0][1]*(k-b)%mod)%mod;
        dfs(l-1,0,0);
        f[l][x][y]=(f[l][x][y]+1LL*f[l-1][0][0]*g(k,b)%mod)%mod;
    }else if(x==1 && y==0){
        dfs(l-1,1,0);
        f[l][x][y]=(f[l][x][y]+1LL*f[l-1][1][0]*(a+1)%mod)%mod;
        dfs(l-1,0,0);
        f[l][x][y]=(f[l][x][y]+1LL*f[l-1][0][0]*g(a,k)%mod)%mod;
    }else{
        dfs(l-1,0,0);
        f[l][x][y]=1LL*f[l-1][0][0]*g(k,k)%mod;
    }
}

int main(){
    scanf("%d%d",&t,&k);
    mi[0]=1;
    for(int i=1;i<N;i++)
        mi[i]=1LL*mi[i-1]*k;
    while(t--){
        scanf("%lld%lld",&n,&m);
        m=min(m,n);
        ans=g(n+1,m+1);
        //printf("%d\n",ans); 
        memset(f,-1,sizeof(f));
        int len=0;
        long long tmp=n;
        while(tmp)
            len++,tmp/=k;
        f[0][0][0]=f[0][0][1]=f[0][1][0]=f[0][1][1]=1;
        dfs(len+1,1,1);
        ans=(ans-f[len+1][1][1]+mod)%mod;
        printf("%d\n",ans);
    }
    return 0;
}
